        if (end > bytes(input).length || begin > end) return (false, address(0));

        bool hasPrefix = (end > begin + 1) && bytes2(_unsafeReadBytesOffset(bytes(input), begin)) == bytes2("0x"); // don't do out-of-bound (possibly unsafe) read if sub-string is empty
        uint256 expectedLength = 40 + hasPrefix.toUint() * 2;

        // check that input is the correct length
        if (end - begin == expectedLength) {
            // length guarantees that this does not overflow, and value is at most type(uint160).max
            (bool s, uint256 v) = _tryParseHexUintUncheckedBounds(input, begin, end);
            return (s, address(uint160(v)));
        } else {
            return (false, address(0));
        }
    }

    function _tryParseChr(bytes1 chr) private pure returns (uint8) {
        uint8 value = uint8(chr);

        // Try to parse `chr`:
        // - Case 1: [0-9]
        // - Case 2: [a-f]
        // - Case 3: [A-F]
        // - otherwise not supported
        unchecked {
            if (value > 47 && value < 58) value -= 48;
            else if (value > 96 && value < 103) value -= 87;
            else if (value > 64 && value < 71) value -= 55;
            else return type(uint8).max;
        }

        return value;
    }

    /**
     * @dev Escape special characters in JSON strings. This can be useful to prevent JSON injection in NFT metadata.
     *
     * WARNING: This function should only be used in double quoted JSON strings. Single quotes are not escaped.
     *
     * NOTE: This function escapes backslashes (including those in \uXXXX sequences) and the characters in ranges
     * defined in section 2.5 of RFC-4627 (U+0000 to U+001F, U+0022 and U+005C). All control characters in U+0000
     * to U+001F are escaped (\b, \t, \n, \f, \r use short form; others use \u00XX). ECMAScript's `JSON.parse` does
     * recover escaped unicode characters that are not in this range, but other tooling may provide different results.
     */
    function escapeJSON(string memory input) internal pure returns (string memory) {
        bytes memory buffer = bytes(input);

        // Put output at the FMP. Memory will be reserved later when we figure out the actual length of the escaped
        // string. All write are done using _unsafeWriteBytesOffset, which avoid the (expensive) length checks for
        // each character written.
        bytes memory output;
        assembly ("memory-safe") {
            output := mload(0x40)
        }
        uint256 outputLength = 0;

        for (uint256 i = 0; i < buffer.length; ++i) {
            uint8 char = uint8(bytes1(_unsafeReadBytesOffset(buffer, i)));
            if (((SPECIAL_CHARS_LOOKUP & (1 << char)) != 0)) {
                _unsafeWriteBytesOffset(output, outputLength++, "\\");
                if (char == 0x08) _unsafeWriteBytesOffset(output, outputLength++, "b");
                else if (char == 0x09) _unsafeWriteBytesOffset(output, outputLength++, "t");
                else if (char == 0x0a) _unsafeWriteBytesOffset(output, outputLength++, "n");
                else if (char == 0x0c) _unsafeWriteBytesOffset(output, outputLength++, "f");
                else if (char == 0x0d) _unsafeWriteBytesOffset(output, outputLength++, "r");
                else if (char == 0x5c) _unsafeWriteBytesOffset(output, outputLength++, "\\");
                else if (char == 0x22) {
                    // solhint-disable-next-line quotes
                    _unsafeWriteBytesOffset(output, outputLength++, '"');
                } else {
                    // U+0000 to U+001F without short form: output \u00XX
                    _unsafeWriteBytesOffset(output, outputLength++, "u");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char >> 4]);
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char & 0x0f]);
                }
            } else {
                _unsafeWriteBytesOffset(output, outputLength++, bytes1(char));
            }
        }
        // write the actual length and reserve memory
        assembly ("memory-safe") {
            mstore(output, outputLength)
            mstore(0x40, add(output, add(outputLength, 0x20)))
        }

        return string(output);
    }

    /**
     * @dev Reads a bytes32 from a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeReadBytesOffset(bytes memory buffer, uint256 offset) private pure returns (bytes32 value) {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            value := mload(add(add(buffer, 0x20), offset))
        }
    }

    /**
     * @dev Write a bytes1 to a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeWriteBytesOffset(bytes memory buffer, uint256 offset, bytes1 value) private pure {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            mstore8(add(add(buffer, 0x20), offset), shr(248, value))
        }
    }
}

contracts/FundDAO.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

// =============================================================================
// FUNDDAO — Contrato de Governanca Descentralizada (DAO simplificada)
// =============================================================================
//
// Este contrato implementa um mecanismo basico de governanca onde os
// detentores de FundToken podem criar propostas e votar nelas. Funciona
// como uma assembleia digital: qualquer detentor de tokens pode propor
// decisoes (ex: aprovar um projeto, alterar regras da plataforma), e os
// demais votam sim ou nao. Se a proposta atingir o quorum minimo e tiver
// maioria de votos a favor, ela e aprovada.
//
// O poder de voto e baseado na quantidade de tokens que o usuario possui
// no momento da votacao: 1 token = 1 voto.
//
// SEGURANCA:
// - Cada endereco so pode votar uma vez por proposta
// - Propostas tem prazo de votacao (nao ficam abertas pra sempre)
// - Apenas o admin pode executar propostas aprovadas
// =============================================================================

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/// @title FundDAO
/// @notice Governanca simplificada para a plataforma de crowdfunding

contract FundDAO is Ownable {

    // Token usado para votacao (1 token = 1 voto)
    IERC20 public fundToken;

    // Duracao padrao de votacao (3 dias em segundos)
    uint256 public duracaoVotacao = 3 days;

    // Quorum minimo: porcentagem de tokens que precisa votar (10%)
    uint256 public quorumMinimo = 10;

    // Contador de propostas
    uint256 public totalPropostas;

    // Estrutura de uma proposta
    struct Proposta {
        string descricao;         // O que esta sendo proposto
        address proponente;       // Quem criou a proposta
        uint256 votosAFavor;      // Total de votos sim
        uint256 votosContra;      // Total de votos nao
        uint256 prazoFinal;       // Timestamp limite para votar
        bool executada;           // Se a proposta ja foi executada
        bool aprovada;            // Se foi aprovada
    }

    // Mapping de ID para proposta
    mapping(uint256 => Proposta) public propostas;

    // Mapping duplo: propostaId => endereco => ja votou?
    mapping(uint256 => mapping(address => bool)) public jaVotou;

    // Eventos
    event PropostaCriada(
        uint256 indexed propostaId,
        address indexed proponente,
        string descricao,
        uint256 prazoFinal
    );

    event VotoRegistrado(
        uint256 indexed propostaId,
        address indexed votante,
        bool aFavor,
        uint256 pesoVoto
    );

    event PropostaExecutada(
        uint256 indexed propostaId,
        bool aprovada
    );

    /// @notice Constructor: recebe o endereco do FundToken
    /// @param _fundToken Endereco do contrato FundToken
    constructor(address _fundToken) Ownable(msg.sender) {
        require(_fundToken != address(0), "Endereco do token invalido");
        fundToken = IERC20(_fundToken);
    }

    /// @notice Cria uma nova proposta
    /// @param _descricao Texto descrevendo a proposta
    /// @dev Qualquer detentor de tokens pode criar uma proposta
    function criarProposta(string memory _descricao) external returns (uint256) {
        // Precisa ter tokens para criar proposta
        require(
            fundToken.balanceOf(msg.sender) > 0,
            "Precisa ter tokens para criar proposta"
        );
        require(bytes(_descricao).length > 0, "Descricao vazia");

        uint256 propostaId = totalPropostas;
        totalPropostas++;

        propostas[propostaId] = Proposta({
            descricao: _descricao,
            proponente: msg.sender,
            votosAFavor: 0,
            votosContra: 0,
            prazoFinal: block.timestamp + duracaoVotacao,
            executada: false,
            aprovada: false
        });

        emit PropostaCriada(propostaId, msg.sender, _descricao, block.timestamp + duracaoVotacao);

        return propostaId;
    }

    /// @notice Registra um voto em uma proposta
    /// @param _propostaId ID da proposta
    /// @param _aFavor true para votar sim, false para votar nao
    function votar(uint256 _propostaId, bool _aFavor) external {
        Proposta storage p = propostas[_propostaId];

        // Validacoes de seguranca
        require(block.timestamp <= p.prazoFinal, "Votacao encerrada");
        require(!p.executada, "Proposta ja executada");
        require(!jaVotou[_propostaId][msg.sender], "Ja votou nesta proposta");

        // Peso do voto = saldo de tokens do votante
        uint256 pesoVoto = fundToken.balanceOf(msg.sender);
        require(pesoVoto > 0, "Precisa ter tokens para votar");

        // Registra o voto
        jaVotou[_propostaId][msg.sender] = true;

        if (_aFavor) {
            p.votosAFavor += pesoVoto;
        } else {
            p.votosContra += pesoVoto;
        }

        emit VotoRegistrado(_propostaId, msg.sender, _aFavor, pesoVoto);
    }

    /// @notice Executa uma proposta apos o prazo de votacao
    /// @param _propostaId ID da proposta
    /// @dev Apenas o admin pode executar. Verifica quorum e maioria.
    function executarProposta(uint256 _propostaId) external onlyOwner {
        Proposta storage p = propostas[_propostaId];

        require(block.timestamp > p.prazoFinal, "Votacao ainda em andamento");
        require(!p.executada, "Proposta ja executada");

        // Calcula quorum: total de votos / total de tokens em circulacao
        uint256 totalVotos = p.votosAFavor + p.votosContra;
        uint256 totalSupply = fundToken.totalSupply();
        uint256 participacao = (totalVotos * 100) / totalSupply;

        // Verifica quorum minimo
        require(participacao >= quorumMinimo, "Quorum minimo nao atingido");

        // Marca como executada
        p.executada = true;

        // Aprovada se maioria votou a favor
        if (p.votosAFavor > p.votosContra) {
            p.aprovada = true;
        }

        emit PropostaExecutada(_propostaId, p.aprovada);
    }

    /// @notice Consulta detalhes de uma proposta
    /// @param _propostaId ID da proposta
    function consultarProposta(uint256 _propostaId)
        external
        view
        returns (
            string memory descricao,
            address proponente,
            uint256 votosAFavor,
            uint256 votosContra,
            uint256 prazoFinal,
            bool executada,
            bool aprovada
        )
    {
        Proposta memory p = propostas[_propostaId];
        return (
            p.descricao,
            p.proponente,
            p.votosAFavor,
            p.votosContra,
            p.prazoFinal,
            p.executada,
            p.aprovada
        );
    }

    /// @notice Verifica se a votacao de uma proposta ainda esta aberta
    function votacaoAberta(uint256 _propostaId) external view returns (bool) {
        return block.timestamp <= propostas[_propostaId].prazoFinal
            && !propostas[_propostaId].executada;
    }

    /// @notice Permite ao admin alterar a duracao da votacao
    function setDuracaoVotacao(uint256 _novaDuracao) external onlyOwner {
        require(_novaDuracao > 0, "Duracao deve ser maior que zero");
        duracaoVotacao = _novaDuracao;
    }

    /// @notice Permite ao admin alterar o quorum minimo
    function setQuorumMinimo(uint256 _novoQuorum) external onlyOwner {
        require(_novoQuorum > 0 && _novoQuorum <= 100, "Quorum invalido");
        quorumMinimo = _novoQuorum;
    }
}

contracts/FundNFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

// =============================================================================
// FUNDNFT — NFT ERC-721 de certificado de apoiador
// =============================================================================
//
// Este contrato implementa NFTs utilizando o padrao ERC-721 da OpenZeppelin.
// O ERC-721 foi escolhido porque cada certificado de apoiador e unico (nao
// fungivel): contem informacoes especificas como o nome do projeto apoiado
// e a data da contribuicao.
//
// Cada apoiador recebe um NFT como comprovante de participacao na plataforma
// de crowdfunding. Esse NFT serve como selo de "apoiador oficial" e pode
// conferir beneficios futuros.
// =============================================================================

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/// @title FundNFT
/// @notice NFT de certificado para apoiadores da plataforma de crowdfunding

contract FundNFT is ERC721, Ownable {

    // Contador de NFTs emitidos (cada NFT tem um ID unico)
    uint256 private _nextTokenId;

    // Estrutura que armazena os dados de cada NFT
    struct CertificadoApoiador {
        string nomeProjeto;
        address apoiador;
        uint256 valorApoio;
        uint256 dataEmissao;
    }

    // Mapping de tokenId para os dados do certificado
    mapping(uint256 => CertificadoApoiador) public certificados;

    // Mapping para verificar se um endereco ja tem NFT de um projeto
    mapping(address => mapping(string => bool)) public jaApoiou;

    // Eventos
    event CertificadoEmitido(
        uint256 indexed tokenId,
        address indexed apoiador,
        string nomeProjeto,
        uint256 valorApoio
    );

    /// @notice Constructor: define nome e simbolo da colecao de NFTs
    constructor() ERC721("FundNFT", "FNFT") Ownable(msg.sender) {}

    /// @notice Emite um certificado NFT para um apoiador
    /// @param _apoiador Endereco do apoiador
    /// @param _nomeProjeto Nome do projeto apoiado
    /// @param _valorApoio Valor da contribuicao em tokens
    /// @dev Apenas o owner (ou contrato autorizado) pode emitir
    function emitirCertificado(
        address _apoiador,
        string memory _nomeProjeto,
        uint256 _valorApoio
    ) external onlyOwner returns (uint256) {
        // Validacoes de seguranca
        require(_apoiador != address(0), "Endereco invalido");
        require(bytes(_nomeProjeto).length > 0, "Nome do projeto vazio");
        require(!jaApoiou[_apoiador][_nomeProjeto], "Ja possui certificado deste projeto");

        // Gera o ID do novo NFT
        uint256 tokenId = _nextTokenId;
        _nextTokenId++;

        // Faz o mint do NFT para o apoiador
        _safeMint(_apoiador, tokenId);

        // Armazena os dados do certificado
        certificados[tokenId] = CertificadoApoiador({
            nomeProjeto: _nomeProjeto,
            apoiador: _apoiador,
            valorApoio: _valorApoio,
            dataEmissao: block.timestamp
        });

        // Marca que esse apoiador ja tem certificado deste projeto
        jaApoiou[_apoiador][_nomeProjeto] = true;

        emit CertificadoEmitido(tokenId, _apoiador, _nomeProjeto, _valorApoio);

        return tokenId;
    }

    /// @notice Consulta os dados de um certificado
    /// @param _tokenId ID do NFT
    function consultarCertificado(uint256 _tokenId)
        external
        view
        returns (
            string memory nomeProjeto,
            address apoiador,
            uint256 valorApoio,
            uint256 dataEmissao
        )
    {
        // Verifica se o NFT existe
        require(_ownerOf(_tokenId) != address(0), "NFT nao existe");

        CertificadoApoiador memory cert = certificados[_tokenId];
        return (cert.nomeProjeto, cert.apoiador, cert.valorApoio, cert.dataEmissao);
    }

    /// @notice Retorna o total de NFTs emitidos
    function totalEmitidos() external view returns (uint256) {
        return _nextTokenId;
    }
}

contracts/FundStaking.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

// =============================================================================
// FUNDSTAKING — Contrato de Staking com integracao de oraculo Chainlink
// =============================================================================
//
// Este contrato permite que apoiadores travem (stake) seus FundTokens e
// recebam recompensas ao longo do tempo. A recompensa e ajustada
// dinamicamente com base no preco do ETH/USD obtido via oraculo Chainlink.
//
// ORACULO:
// Oraculos sao servicos que trazem dados do mundo real para dentro da
// blockchain. A blockchain, por si so, nao consegue acessar APIs externas
// ou dados fora da rede. O Chainlink resolve isso de forma descentralizada
// e confiavel. Aqui, usamos o price feed ETH/USD para ajustar a recompensa:
// quando o ETH esta mais caro, a recompensa em tokens e menor; quando
// esta mais barato, a recompensa e maior.
//
// SEGURANCA:
// - ReentrancyGuard: protege contra ataques de reentrancy, onde um contrato
//   malicioso tenta chamar a funcao de saque repetidamente antes que o saldo
//   seja atualizado.
// - Ownable: garante que apenas o admin execute funcoes administrativas.
// =============================================================================

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@chainlink/contracts/src/v0.8/shared/interfaces/AggregatorV3Interface.sol";

/// @title FundStaking
/// @notice Staking de FundTokens com recompensa ajustada por oraculo Chainlink

contract FundStaking is ReentrancyGuard, Ownable {

    // Token ERC-20 usado no staking
    IERC20 public fundToken;

    // Oraculo Chainlink para preco ETH/USD
    AggregatorV3Interface public priceFeed;

    // Taxa base de recompensa (tokens por segundo por token em stake, x10^18)
    uint256 public taxaRecompensa = 100;

    // Estrutura dos dados de cada staker
    struct Staker {
        uint256 saldoStake;        // Quantidade de tokens em stake
        uint256 recompensaAcumulada; // Recompensa pendente
        uint256 ultimaAtualizacao;  // Timestamp da ultima atualizacao
    }

    // Mapping de endereco para dados do staker
    mapping(address => Staker) public stakers;

    // Total de tokens em stake no contrato
    uint256 public totalStaked;

    // Eventos
    event Staked(address indexed usuario, uint256 quantidade);
    event Unstaked(address indexed usuario, uint256 quantidade);
    event RecompensaResgatada(address indexed usuario, uint256 quantidade);

    /// @notice Constructor: recebe endereco do token e do oraculo
    /// @param _fundToken Endereco do contrato FundToken
    /// @param _priceFeed Endereco do oraculo Chainlink ETH/USD
    constructor(
        address _fundToken,
        address _priceFeed
    ) Ownable(msg.sender) {
        require(_fundToken != address(0), "Endereco do token invalido");
        require(_priceFeed != address(0), "Endereco do oraculo invalido");
        fundToken = IERC20(_fundToken);
        priceFeed = AggregatorV3Interface(_priceFeed);
    }

    /// @notice Consulta o preco atual do ETH em USD via Chainlink
    /// @return Preco do ETH em USD (8 casas decimais)
    function obterPrecoETH() public view returns (uint256) {
        (
            ,
            int256 preco,
            ,
            ,
        ) = priceFeed.latestRoundData();
        require(preco > 0, "Preco invalido do oraculo");
        return uint256(preco);
    }

    /// @notice Calcula a recompensa ajustada pelo preco do ETH
    /// @dev Quando ETH esta caro (>2000 USD), recompensa diminui.
    ///      Quando ETH esta barato (<2000 USD), recompensa aumenta.
    /// @param _staker Endereco do staker
    /// @return Recompensa calculada
    function calcularRecompensa(address _staker) public view returns (uint256) {
        Staker memory s = stakers[_staker];
        if (s.saldoStake == 0) return 0;

        uint256 tempoDecorrido = block.timestamp - s.ultimaAtualizacao;
        uint256 precoETH = obterPrecoETH();

        // Preco base de referencia: 2000 USD (com 8 decimais do Chainlink)
        uint256 precoBase = 2000 * 10 ** 8;

        // Ajuste: recompensa = base * (precoBase / precoAtual)
        // Se ETH > 2000 USD, recompensa diminui
        // Se ETH < 2000 USD, recompensa aumenta
        uint256 recompensa = (s.saldoStake * taxaRecompensa * tempoDecorrido * precoBase)
            / (precoETH * 10 ** 18);

        return recompensa;
    }

    /// @notice Atualiza a recompensa acumulada de um staker
    /// @param _staker Endereco do staker
    function _atualizarRecompensa(address _staker) internal {
        stakers[_staker].recompensaAcumulada += calcularRecompensa(_staker);
        stakers[_staker].ultimaAtualizacao = block.timestamp;
    }

    /// @notice Deposita tokens em stake
    /// @param _quantidade Quantidade de tokens a serem travados
    /// @dev O usuario precisa aprovar (approve) o contrato antes de chamar esta funcao
    function stake(uint256 _quantidade) external nonReentrant {
        require(_quantidade > 0, "Quantidade deve ser maior que zero");
        require(
            fundToken.balanceOf(msg.sender) >= _quantidade,
            "Saldo insuficiente"
        );

        // Atualiza recompensa pendente antes de alterar o saldo
        _atualizarRecompensa(msg.sender);

        // Transfere tokens do usuario para o contrato
        fundToken.transferFrom(msg.sender, address(this), _quantidade);

        // Atualiza saldo do staker
        stakers[msg.sender].saldoStake += _quantidade;
        totalStaked += _quantidade;

        emit Staked(msg.sender, _quantidade);
    }

    /// @notice Retira tokens do stake
    /// @param _quantidade Quantidade de tokens a serem retirados
    function unstake(uint256 _quantidade) external nonReentrant {
        require(_quantidade > 0, "Quantidade deve ser maior que zero");
        require(
            stakers[msg.sender].saldoStake >= _quantidade,
            "Saldo em stake insuficiente"
        );

        // Atualiza recompensa pendente antes de alterar o saldo
        _atualizarRecompensa(msg.sender);

        // Atualiza saldo do staker
        stakers[msg.sender].saldoStake -= _quantidade;
        totalStaked -= _quantidade;

        // Devolve tokens ao usuario
        fundToken.transfer(msg.sender, _quantidade);

        emit Unstaked(msg.sender, _quantidade);
    }

    /// @notice Resgata as recompensas acumuladas
    function resgatarRecompensa() external nonReentrant {
        _atualizarRecompensa(msg.sender);

        uint256 recompensa = stakers[msg.sender].recompensaAcumulada;
        require(recompensa > 0, "Sem recompensa disponivel");

        // Zera a recompensa antes de transferir (previne reentrancy)
        stakers[msg.sender].recompensaAcumulada = 0;

        // Transfere recompensa em tokens
        fundToken.transfer(msg.sender, recompensa);

        emit RecompensaResgatada(msg.sender, recompensa);
    }

    /// @notice Permite ao admin alterar a taxa de recompensa
    /// @param _novaTaxa Nova taxa de recompensa
    function setTaxaRecompensa(uint256 _novaTaxa) external onlyOwner {
        require(_novaTaxa > 0, "Taxa deve ser maior que zero");
        taxaRecompensa = _novaTaxa;
    }

    /// @notice Consulta saldo em stake de um usuario
    function saldoEmStake(address _usuario) external view returns (uint256) {
        return stakers[_usuario].saldoStake;
    }

    /// @notice Consulta recompensa pendente de um usuario
    function recompensaPendente(address _usuario) external view returns (uint256) {
        return stakers[_usuario].recompensaAcumulada + calcularRecompensa(_usuario);
    }
}

contracts/FundToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

// =============================================================================
// FUNDTOKEN — Token ERC-20 da plataforma de crowdfunding
// =============================================================================
//
// Este contrato implementa o token fungivel da plataforma utilizando o padrao
// ERC-20 da OpenZeppelin. O ERC-20 foi escolhido porque todos os tokens sao
// iguais entre si (fungiveis), funcionando como moeda interna da plataforma.
// O token serve para: apoiar projetos, votar na DAO e fazer staking.
//
// A OpenZeppelin e uma biblioteca auditada e amplamente utilizada no mercado,
// o que reduz riscos de seguranca ao evitar reimplementacoes manuais.
// =============================================================================

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/// @title FundToken
/// @notice Token ERC-20 da plataforma de crowdfunding para pequenos negocios de tecnologia

contract FundToken is ERC20, Ownable {

    // Preco do token em wei (0.001 ETH por token)
    uint256 public tokenPrice = 0.001 ether;

    // Eventos
    event TokensPurchased(address indexed buyer, uint256 amount, uint256 cost);

    /// @notice Constructor: define nome, simbolo e faz mint inicial para o deployer
    /// @dev O deployer recebe 1.000.000 de tokens como supply inicial
    constructor() ERC20("FundToken", "FUND") Ownable(msg.sender) {
        // Mint inicial de 1.000.000 tokens para o admin (18 decimais)
        _mint(msg.sender, 1_000_000 * 10 ** decimals());
    }

    /// @notice Permite que qualquer pessoa compre tokens enviando ETH
    /// @dev O valor em ETH e convertido em tokens com base no tokenPrice
    function buyTokens() external payable {
        require(msg.value > 0, "Envie ETH para comprar tokens");

        // Calcula quantos tokens o comprador recebe
        uint256 amount = (msg.value * 10 ** decimals()) / tokenPrice;
        require(amount > 0, "ETH insuficiente para comprar tokens");

        // Transfere tokens do owner para o comprador
        _transfer(owner(), msg.sender, amount);

        emit TokensPurchased(msg.sender, amount, msg.value);
    }

    /// @notice Permite ao admin criar novos tokens (mint)
    /// @param _to Endereco que recebera os tokens
    /// @param _amount Quantidade de tokens a serem criados
    function mint(address _to, uint256 _amount) external onlyOwner {
        _mint(_to, _amount);
    }

    /// @notice Permite ao admin alterar o preco do token
    /// @param _newPrice Novo preco em wei
    function setTokenPrice(uint256 _newPrice) external onlyOwner {
        require(_newPrice > 0, "Preco deve ser maior que zero");
        tokenPrice = _newPrice;
    }

    /// @notice Permite ao admin retirar o ETH acumulado no contrato
    function withdraw() external onlyOwner {
        uint256 balance = address(this).balance;
        require(balance > 0, "Sem ETH para retirar");
        payable(owner()).transfer(balance);
    }
}

